#include <bits/stdc++.h>
using namespace std;
int t,n,a[50004],ans=0;
bool check(int l,int r){
    if(a[l]>=0 || a[r]<=0)
        return max(abs(a[r]),abs(a[l]))<=t;
    else
        return abs(a[l])+abs(a[r])+min(abs(a[l]),abs(a[r]))<=t;
}
int main(){
    cin>>t>>n;
    for(int i=1;i<=n;i++)
        cin>>a[i];
    sort(a+1,a+n+1);
    for(int i=1;i<=n;i++){
        if(!check(i,i))
            continue;
        int l=i,r=n;
        while(l<r){
            int mid=(l+r+1)/2;
            if(check(i,mid))
                l=mid;
            else
                r=mid-1;
        }
        ans=max(ans,r-i+1);
    }
    printf("%d",ans);
    return 0;
}
